        std::cout << "-i,  --input=<string>,  File path for input file [repeated, min args = 1]\n";
        std::cout << "-s,  --flag1,  Use some logic [default = true]\n";
        std::cout << "-p,  --flag2,  Use some logic\n";
        std::cout << "     --number=<int>,  Some Number\n\n";
