    bool ArgParser::Parse(std::vector<std::string> args) {
        if (all_.empty() && args.size() == 1) {
            return true;
        }
        int count = 0;
        for (int i = 0; i < args.size(); ++i) {
            for (auto& arg : all_) {
                switch (arg->GetType()) {
                    case Type::STRING: {
                        String* temp = static_cast<String*>(arg);
                        std::string origin_param = "--" + temp->GetParam() + "=";
                        std::string origin_short_param = "-";
                        origin_short_param.push_back(temp->GetShortParam());
                        origin_short_param += "=";
                        Int* arg = static_cast<Int*>(arg);
                        if (args.size() == 1 && !temp->GetDefaultValue().empty()) {
                            temp->PutValue(temp->GetDefaultValue());
                            ++count;
                        } else if (!temp->GetParam().empty() && args[i].substr(0, origin_param.length()) == origin_param && !temp->GetFlagMultiValue()) {
                            temp->PutValue(args[i].substr(origin_param.length(), args[i].length()));
                            if (temp->GetFlagStoreValue()) {
                                temp->AddStoreValue(temp->GetValue());
                            }
                            ++count;
                        } else if (temp->GetFlagShortParam() && args[i].substr(0, origin_short_param.length()) == origin_short_param && !temp->GetFlagMultiValue()) {
                            temp->PutValue(args[i].substr(origin_short_param.length(), args[i].length()));
                            if (temp->GetFlagStoreValue()) {
                                temp->AddStoreValue(temp->GetValue());
                            }
                            ++count;
                        } else if (temp->GetFlagMultiValue()) {
                            if (args[i].substr(0, origin_param.length()) == origin_param) {
                                temp->PutValue(args[i].substr(origin_param.length(), args[i].length()));
                                temp->MultiArgsCount();
                            } else if (temp->GetFlagShortParam() && args[i].substr(0, origin_short_param.length()) == origin_short_param) {
                                temp->PutValue(args[i].substr(origin_short_param.length(), args[i].length()));
                                temp->MultiArgsCount();
                            }
                            /*if (args[i][0] == '-' && arg->GetFlagStoreValues()) {
                                arg->AddStoreValues(temp->GetValue());
                                temp->AddAllValues(temp->GetValue());
                            }*/
                        }
                        break;
                    }
                    case Type::INT: {
                        Int* arg = static_cast<Int*>(arg);

                        // Parsing logic for integer arguments.
                        break;
                    }
                    case Type::BOOL: {
                        Bool* temp = static_cast<Bool*>(arg);
                        std::string origin_flag = "--" + temp->GetFlag();
                        if (temp->GetIsFlag()) {
                            if (args[i].substr(0, origin_flag.length()) == origin_flag) {
                                if (temp->GetFlagStoreFlag()) {
                                    temp->AddStoreFlag(true);
                                    }
                                    ++count;
                            } else if (args[i][0] == '-' && args[i][1] != '-' && args[i].length() > 2) {
                                for (int z = 1; z < args[i].length(); ++z) {
                                    if (args[i][z] == temp->GetShortFlag()) {
                                        if (temp->GetFlagStoreFlag()) {
                                        temp->AddStoreFlag(true);
                                        }
                                        ++count;
                                    }
                                }
                            }
                            break;
                        }
                    }
                    std::string origin_help = "--" + arg->GetHelp();
                    std::string origin_short_help = "-";
                    origin_short_help.push_back(arg->GetShortHelp());
                    if (arg->GetFlagPositional()) {
                        int count_len = 0;
                        for (int k = 0; k < args[i].length(); ++k) {
                            if (!std::isdigit(args[i][k])){
                                break;
                            } else {
                                ++count_len;
                            }
                        }
                        if (count_len == args[i].length()) {
                            /*arg->PutValue(args[i]);
                            arg->MultiArgsCount();
                            if (arg->GetFlagStoreValues()) {
                                arg->AddStoreValues(all_[j]->GetValue());
                                all_[j]->AddAllValues(all_[j]->GetValue());
                            }*/
                        }
                    } else if (args[i].substr(0, origin_help.length()) == origin_help || args[i].substr(0, origin_short_help.length()) == origin_short_help) {
                        arg->FlagHelp();
                        ++count;
                    }
                }
            }
        }
        for (int i = 0; i < all_.size(); ++i) {
            if (all_[i]->GetMultiArgsCount() > 0) {
                ++count;
            }
            if (static_cast<Bool*>(all_[i])->GetFlagDefaultFlag()) {
                ++count;
            }
            if (all_[i]->GetMultiArgsCount() > 0 && all_[i]->GetMinArgsCount() > all_[i]->GetMultiArgsCount()) {
                return false;
            }
        }
